/**
 * Fire Alarm System Test Examples
 * US4.3: Brandalarm Implementation
 * 
 * This file shows practical examples of how to use the Fire Alarm system
 * in your Hotel Simulator.
 */

package model;

public class FireAlarmExample {

    /**
     * Example 1: Basic Fire Alarm Trigger
     * 
     * This demonstrates how to trigger a fire alarm and observe evacuation
     */
    public static void example1_BasicFireAlarm(Simulator simulator) {
        System.out.println("\n=== EXAMPLE 1: Basic Fire Alarm ===\n");

        // Start the simulation
        simulator.start();

        // Let simulation run for a bit
        try { Thread.sleep(5000); } catch (Exception e) {}

        // Trigger fire alarm
        System.out.println("\n>>> Triggering fire alarm...");
        simulator.triggerFireAlarm();

        // Observe evacuation for 10 seconds
        try { Thread.sleep(10000); } catch (Exception e) {}

        // Clear alarm
        System.out.println("\n>>> Clearing fire alarm...");
        simulator.clearFireAlarm();

        // Observe recovery for 5 seconds
        try { Thread.sleep(5000); } catch (Exception e) {}

        simulator.pause();
    }

    /**
     * Example 2: Fire Alarm with Multiple People
     * 
     * Shows fire alarm behavior with various guests in different activities
     */
    public static void example2_WithMultiplePeople(Simulator simulator) {
        System.out.println("\n=== EXAMPLE 2: Fire Alarm with Multiple People ===\n");

        simulator.start();

        // Let simulation run for a bit to populate with guests
        try { Thread.sleep(15000); } catch (Exception e) {}

        // Trigger fire alarm
        System.out.println("\n>>> Fire alarm triggered!");
        simulator.triggerFireAlarm();

        // All guests will immediately evacuate
        try { Thread.sleep(15000); } catch (Exception e) {}

        simulator.pause();
    }

    /**
     * Example 3: Observing Elevator Behavior During Fire Alarm
     * 
     * Demonstrates how the elevator is disabled and passengers ejected
     */
    public static void example3_ElevatorBehavior(Simulator simulator) {
        System.out.println("\n=== EXAMPLE 3: Elevator Behavior During Fire Alarm ===\n");

        simulator.start();

        // Let simulation run so people use elevators
        try { Thread.sleep(10000); } catch (Exception e) {}

        // Check if anyone is in the lift
        Lift lift = simulator.getLift();
        if (lift != null && lift.getPassagiers().size() > 0) {
            System.out.println(">>> " + lift.getPassagiers().size() + " people in lift");
            System.out.println(">>> Triggering fire alarm - they will be ejected!");

            simulator.triggerFireAlarm();

            // Immediately after alarm
            try { Thread.sleep(100); } catch (Exception e) {}

            System.out.println(">>> People in lift after alarm: " + lift.getPassagiers().size());
            // Should be 0 - all ejected!
        }

        try { Thread.sleep(10000); } catch (Exception e) {}

        simulator.pause();
    }

    /**
     * Example 4: Checking Evacuation Status
     * 
     * Shows how to verify that people are in evacuation state
     */
    public static void example4_EvacuationStatus(Simulator simulator, Hotel hotel) {
        System.out.println("\n=== EXAMPLE 4: Evacuation Status Monitoring ===\n");

        simulator.start();

        try { Thread.sleep(5000); } catch (Exception e) {}

        simulator.triggerFireAlarm();

        // Check evacuation status after alarm
        try { Thread.sleep(2000); } catch (Exception e) {}

        int evacuating = 0;
        int inLobby = 0;

        for (Persoon p : hotel.getPersonen()) {
            if (p.isFireAlarmActive()) {
                if (p.isEvacuatieBegonnen()) {
                    // Check if they're in lobby (X position near 1.5)
                    if (Math.abs(p.getX() - 1.5) < 0.5) {
                        inLobby++;
                    } else {
                        evacuating++;
                    }
                }
            }
        }

        System.out.println("\n>>> Evacuation Status:");
        System.out.println("    Currently evacuating: " + evacuating);
        System.out.println("    Reached lobby: " + inLobby);

        try { Thread.sleep(10000); } catch (Exception e) {}

        simulator.clearFireAlarm();
        simulator.pause();
    }

    /**
     * Example 5: Multiple Fire Alarms (Stress Test)
     * 
     * Tests system behavior with multiple alarm triggers and clears
     */
    public static void example5_MultipleAlarms(Simulator simulator) {
        System.out.println("\n=== EXAMPLE 5: Multiple Fire Alarms ===\n");

        simulator.start();

        for (int alarmCount = 1; alarmCount <= 3; alarmCount++) {
            try { Thread.sleep(5000); } catch (Exception e) {}

            System.out.println("\n>>> ALARM #" + alarmCount);
            simulator.triggerFireAlarm();

            try { Thread.sleep(8000); } catch (Exception e) {}

            System.out.println(">>> Clearing alarm #" + alarmCount);
            simulator.clearFireAlarm();
        }

        try { Thread.sleep(5000); } catch (Exception e) {}

        simulator.pause();
    }

    /**
     * Example 6: Integration Test - Full Simulation Cycle
     * 
     * Complete test including guest activity, then fire alarm, 
     * then recovery to normal operations
     */
    public static void example6_FullCycle(Simulator simulator) {
        System.out.println("\n=== EXAMPLE 6: Full Simulation Cycle ===\n");

        simulator.start();

        // Phase 1: Normal operations
        System.out.println("\n[Phase 1] Normal Operations (15 seconds)");
        try { Thread.sleep(15000); } catch (Exception e) {}

        // Phase 2: Fire Alarm
        System.out.println("\n[Phase 2] Emergency Evacuation (20 seconds)");
        simulator.triggerFireAlarm();
        try { Thread.sleep(20000); } catch (Exception e) {}

        // Phase 3: All Clear
        System.out.println("\n[Phase 3] All Clear - Resuming Normal Operations (10 seconds)");
        simulator.clearFireAlarm();
        try { Thread.sleep(10000); } catch (Exception e) {}

        simulator.pause();
        System.out.println("\n[COMPLETE] Test cycle finished\n");
    }

    /**
     * Verification Helper: Check if all people are in lobby after evacuation
     */
    public static boolean verifyAllInLobby(Hotel hotel) {
        for (Persoon p : hotel.getPersonen()) {
            if (Math.abs(p.getX() - 1.5) > 0.5) {
                System.out.println("NOT in lobby: " + p.getNaam() + " at X=" + p.getX());
                return false;
            }
        }
        System.out.println("✓ Verification: All people in lobby!");
        return true;
    }

    /**
     * Verification Helper: Check if lift is disabled
     */
    public static boolean verifyLiftDisabled(Lift lift) {
        if (lift.isFireAlarmActive()) {
            System.out.println("✓ Verification: Lift properly disabled!");
            return true;
        }
        System.out.println("✗ Verification: Lift should be disabled!");
        return false;
    }

    /**
     * Verification Helper: Check if all people have evacuation flag set
     */
    public static boolean verifyAllEvacuating(Hotel hotel) {
        for (Persoon p : hotel.getPersonen()) {
            if (!p.isFireAlarmActive()) {
                System.out.println("NOT evacuating: " + p.getNaam());
                return false;
            }
        }
        System.out.println("✓ Verification: All people have evacuation flag!");
        return true;
    }
}

package model;

import model.*;
import ui.HotelPanel;

/**
 * Quick Test: Fire Alarm System
 * US4.3: Brandalarm - Simulation Test
 */
public class FireAlarmTest {

    public static void main(String[] args) throws Exception {
        System.out.println("\n╔════════════════════════════════════════════════════════════════╗");
        System.out.println("║  FIRE ALARM SYSTEM (US4.3: BRANDALARM) - TEST SIMULATION      ║");
        System.out.println("╚════════════════════════════════════════════════════════════════╝\n");

        // Load hotel layout
        System.out.println("Loading hotel layout...");
        Hotel hotel = LayoutLoader.laadLayout("layouts/hotel_multistory.json");

        // Initialize rooms
        System.out.println("Initializing rooms...");
        initializeKamers(hotel);

        // Add guests
        System.out.println("Adding guests...");
        addTestGuests(hotel);

        // Add staff
        System.out.println("Adding staff...");
        addSchoonmakers(hotel);

        System.out.println("\n✓ Initial setup complete!\n");

        // Create simulator and panel
        HotelPanel panel = new HotelPanel(hotel);
        Simulator simulator = new Simulator(hotel, panel);

        System.out.println("Starting simulation...\n");
        simulator.start();

        // Phase 1: Normal operations
        System.out.println("\n" + "=".repeat(70));
        System.out.println("PHASE 1: Normal Operations (5 seconds)");
        System.out.println("=".repeat(70));
        for (int i = 0; i < 50; i++) {
            simulator.tick();
            Thread.sleep(100);
        }

        // Show status before alarm
        printPersonStatus(hotel, "BEFORE ALARM");

        // Phase 2: Trigger fire alarm
        System.out.println("\n" + "=".repeat(70));
        System.out.println("PHASE 2: TRIGGERING FIRE ALARM");
        System.out.println("=".repeat(70));
        simulator.triggerFireAlarm();

        // Let them start evacuating
        Thread.sleep(500);

        // Run evacuation simulation
        System.out.println("\n" + "=".repeat(70));
        System.out.println("PHASE 3: Evacuation in progress (10 seconds)");
        System.out.println("=".repeat(70));

        for (int i = 0; i < 100; i++) {
            simulator.tick();
            if (i % 20 == 0) {
                printEvacuationStatus(hotel);
            }
            Thread.sleep(100);
        }

        // Show status during alarm
        printPersonStatus(hotel, "DURING EVACUATION");

        // Phase 3: Clear alarm
        System.out.println("\n" + "=".repeat(70));
        System.out.println("PHASE 4: Clearing Fire Alarm");
        System.out.println("=".repeat(70));
        simulator.clearFireAlarm();

        // Wait a bit
        Thread.sleep(1000);

        // Show final status
        printPersonStatus(hotel, "AFTER ALARM CLEARED");

        simulator.pause();

        System.out.println("\n╔════════════════════════════════════════════════════════════════╗");
        System.out.println("║  ✅ TEST COMPLETE - Fire Alarm System Working!                  ║");
        System.out.println("╚════════════════════════════════════════════════════════════════╝\n");

        System.exit(0);
    }

    private static void initializeKamers(Hotel hotel) {
        java.util.List<Area> roomAreas = new java.util.ArrayList<>();
        for (Area a : hotel.getAreas()) {
            if ("Room".equals(a.getAreaType())) roomAreas.add(a);
        }

        int[] nummers = {101, 102, 201, 202};
        String[] types = {"Luxe", "Luxe", "Standaard", "Standaard"};

        for (int i = 0; i < nummers.length && i < roomAreas.size(); i++) {
            Kamer k = new Kamer(nummers[i], types[i]);
            k.setArea(roomAreas.get(i));
            hotel.addKamer(k);
        }
    }

    private static void addTestGuests(Hotel hotel) {
        String[] namen = {"Alice", "Bob", "Charlie", "Diana"};
        for (String naam : namen) {
            Gast g = new Gast(naam, -1, 0);
            g.setHotel(hotel);
            g.setStartPositie(-1.0, 6.5);
            hotel.addPersoon(g);
        }
    }

    private static void addSchoonmakers(Hotel hotel) {
        Schoonmaker s1 = new Schoonmaker("Schoonmaker1", 8, 6);
        Schoonmaker s2 = new Schoonmaker("Schoonmaker2", 8, 6);
        s1.setHotel(hotel);
        s2.setHotel(hotel);
        hotel.addPersoon(s1);
        hotel.addPersoon(s2);
    }

    private static void printPersonStatus(Hotel hotel, String phase) {
        System.out.println("\n>>> STATUS: " + phase);
        System.out.println("┌─────────────────────────────────────────────────────────────┐");
        for (Persoon p : hotel.getPersonen()) {
            String type = (p instanceof Gast) ? " Guest" : " Staff";
            String activity = p.getHuidigeActiviteit();
            String alarm = p.isFireAlarmActive() ? " ALARM" : "✓ OK";
            System.out.printf("│ %s %-20s Activity: %-20s %s%n", 
                type, p.getNaam(), activity, alarm);
        }
        System.out.println("└─────────────────────────────────────────────────────────────┘");
    }

    private static void printEvacuationStatus(Hotel hotel) {
        int inLobby = 0;
        int evacuating = 0;
        int notEvacuating = 0;

        for (Persoon p : hotel.getPersonen()) {
            if (p.isFireAlarmActive()) {
                if (Math.abs(p.getX() - 1.5) < 0.5) {
                    inLobby++;
                } else {
                    evacuating++;
                }
            } else {
                notEvacuating++;
            }
        }

        System.out.printf("   Status: In Lobby: %d | Evacuating: %d | Not Active: %d%n", 
            inLobby, evacuating, notEvacuating);
    }
}

package model;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Lift implements TickListener {

    private double x, y;
    private int schachtMinY;
    private int schachtMaxY;

    private List<Persoon> passagiers;
    private Map<Persoon, Integer> passengerDestinations;

    private static final int MAX_CAPACITY = 3;
    private static final double LIFT_SPEED = 0.3;
    private static final int STATION_WAIT_TICKS = 15;

    private enum LiftState { MOVING_UP, MOVING_DOWN, AT_STATION }
    private LiftState state = LiftState.MOVING_UP;

    private int currentFloor;
    private boolean movingUp = true;
    private int stationWaitCounter = 0;

    public Lift(double startX, double startY, int schachtMinY, int schachtMaxY) {
        this.x = startX;
        this.y = startY;
        this.schachtMinY = schachtMinY;
        this.schachtMaxY = schachtMaxY;
        this.passagiers = new ArrayList<>();
        this.passengerDestinations = new HashMap<>();
        this.currentFloor = (int)(startY - 0.5);
        this.movingUp = (startY < (schachtMinY + schachtMaxY) / 2.0 + 0.5);
    }

    public void roepNaar(int verdieping) {
        // Legacy method
    }

    public boolean voegGastToe(Persoon persoon, int doelVerdieping) {
        int persoonFloor = (persoon instanceof Gast) 
            ? (int)((Gast) persoon).getY() 
            : (int)((Schoonmaker) persoon).getY();

        if (Math.abs(persoonFloor - currentFloor) > 0 || state != LiftState.AT_STATION) {
            return false;
        }

        if (passagiers.size() >= MAX_CAPACITY) {
            return false;
        }

        passagiers.add(persoon);
        passengerDestinations.put(persoon, doelVerdieping);
        System.out.println("[Lift] " + persoon.getNaam() + " ingestapt op verdieping " + currentFloor);
        return true;
    }

    public void verwijderGast(Persoon persoon) {
        if (passagiers.remove(persoon)) {
            passengerDestinations.remove(persoon);
            System.out.println("[Lift] " + persoon.getNaam() + " uitgestapt op verdieping " + currentFloor);
        }
    }

    @Override
    public void onTick() {
        syncPassagierPosities();

        if (stationWaitCounter > 0) {
            state = LiftState.AT_STATION;
            stationWaitCounter--;

            if (stationWaitCounter == 0) {
                determineNextFloor();
            }
            return;
        }

        double targetY = currentFloor + 0.5;
        double distance = Math.abs(targetY - y);

        if (distance < 0.15) {
            y = targetY;
            state = LiftState.AT_STATION;
            stationWaitCounter = STATION_WAIT_TICKS;
            return;
        }

        if (targetY > y) {
            state = LiftState.MOVING_UP;
            y = Math.min(y + LIFT_SPEED, targetY);
        } else {
            state = LiftState.MOVING_DOWN;
            y = Math.max(y - LIFT_SPEED, targetY);
        }
    }

    private void determineNextFloor() {
        if (movingUp) {
            currentFloor++;
            if (currentFloor >= schachtMaxY) {
                currentFloor = schachtMaxY - 1;
                movingUp = false;
            }
        } else {
            currentFloor--;
            if (currentFloor <= schachtMinY) {
                currentFloor = schachtMinY + 1;
                movingUp = true;
            }
        }
    }

    private void syncPassagierPosities() {
        for (Persoon p : passagiers) {
            p.setLiftPosition(this.x, this.y);
        }
    }

    public double getX() { return x; }
    public double getY() { return y; }
    public int getCurrentFloor() { return currentFloor; }
    public boolean isIdle() { return state == LiftState.AT_STATION; }
    public List<Persoon> getPassagiers() { return new ArrayList<>(passagiers); }
    public int getDestination(Persoon p) { return passengerDestinations.getOrDefault(p, -1); }
}

package model;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Lift implements TickListener {

    private double x, y;
    private int schachtMinY;
    private int schachtMaxY;

    private List<Persoon> passagiers;
    private Map<Persoon, Integer> passengerDestinations;

    private static final int MAX_CAPACITY = 3;
    private static final double LIFT_SPEED = 0.3;
    private static final int STATION_WAIT_TICKS = 15;

    private boolean fireAlarmActive = false;

    private enum LiftState { MOVING_UP, MOVING_DOWN, AT_STATION }
    private LiftState state = LiftState.MOVING_UP;

    private int currentFloor;
    private boolean movingUp = true;
    private int stationWaitCounter = 0;

    public Lift(double startX, double startY, int schachtMinY, int schachtMaxY) {
        this.x = startX;
        this.y = startY;
        this.schachtMinY = schachtMinY;
        this.schachtMaxY = schachtMaxY;
        this.passagiers = new ArrayList<>();
        this.passengerDestinations = new HashMap<>();
        this.currentFloor = (int)(startY - 0.5);
        this.movingUp = (startY < (schachtMinY + schachtMaxY) / 2.0 + 0.5);
    }

    public void roepNaar(int verdieping) {
        // Legacy method
    }

    public boolean voegGastToe(Persoon persoon, int doelVerdieping) {
        // Reject during fire alarm
        if (fireAlarmActive) {
            return false;
        }

        int persoonFloor = (persoon instanceof Gast) 
            ? (int)((Gast) persoon).getY() 
            : (int)((Schoonmaker) persoon).getY();

        if (Math.abs(persoonFloor - currentFloor) > 0 || state != LiftState.AT_STATION) {
            return false;
        }

        if (passagiers.size() >= MAX_CAPACITY) {
            return false;
        }

        passagiers.add(persoon);
        passengerDestinations.put(persoon, doelVerdieping);
        System.out.println("[Lift] " + persoon.getNaam() + " ingestapt op verdieping " + currentFloor);
        return true;
    }

    public void verwijderGast(Persoon persoon) {
        if (passagiers.remove(persoon)) {
            passengerDestinations.remove(persoon);
            System.out.println("[Lift] " + persoon.getNaam() + " uitgestapt op verdieping " + currentFloor);
        }
    }

    @Override
    public void onTick() {
        syncPassagierPosities();

        if (stationWaitCounter > 0) {
            state = LiftState.AT_STATION;
            stationWaitCounter--;

            if (stationWaitCounter == 0) {
                determineNextFloor();
            }
            return;
        }

        double targetY = currentFloor + 0.5;
        double distance = Math.abs(targetY - y);

        if (distance < 0.15) {
            y = targetY;
            state = LiftState.AT_STATION;
            stationWaitCounter = STATION_WAIT_TICKS;
            return;
        }

        if (targetY > y) {
            state = LiftState.MOVING_UP;
            y = Math.min(y + LIFT_SPEED, targetY);
        } else {
            state = LiftState.MOVING_DOWN;
            y = Math.max(y - LIFT_SPEED, targetY);
        }
    }

    private void determineNextFloor() {
        if (movingUp) {
            currentFloor++;
            if (currentFloor > schachtMaxY) {
                currentFloor = schachtMaxY;
                movingUp = false;
            }
        } else {
            currentFloor--;
            if (currentFloor < schachtMinY) {
                currentFloor = schachtMinY;
                movingUp = true;
            }
        }
    }

    private void syncPassagierPosities() {
        for (Persoon p : passagiers) {
            p.setLiftPosition(this.x, this.y);
        }
    }

    public double getX() { return x; }
    public double getY() { return y; }
    public int getCurrentFloor() { return currentFloor; }
    public boolean isIdle() { return state == LiftState.AT_STATION; }
    public List<Persoon> getPassagiers() { return new ArrayList<>(passagiers); }
    public int getDestination(Persoon p) { return passengerDestinations.getOrDefault(p, -1); }

    // Fire alarm methods
    public void activeerFireAlarm() {
        this.fireAlarmActive = true;
        System.out.println("[Lift]  FIRE ALARM: Lift disabled, all passengers being evacuated!");

        // Immediately eject all passengers to nearest floor
        for (Persoon p : new ArrayList<>(passagiers)) {
            verwijderGast(p);
        }
    }

    public void deactiveerFireAlarm() {
        this.fireAlarmActive = false;
        System.out.println("[Lift] ✓ Fire alarm cleared, lift returning to normal operation");
    }

    public boolean isFireAlarmActive() { return fireAlarmActive; }
}

package model;

/**
 * Basisklasse voor alle personen
 */
public abstract class Persoon implements TickListener {

    private static int volgendeId = 1;

    private int id;
    private String naam;
    private String type;
    protected String huidigeActiviteit = ""; // Wat is de persoon aan het doen?

    // 'protected' zodat subclasses (Gast, Schoonmaker) ze kunnen gebruiken
    protected double x;
    protected double y;
    protected double destX;
    protected double destY; // destY toegevoegd voor volledige bewegingsvrijheid

    public Persoon(String naam, String type) {
        this.id = volgendeId++;
        this.naam = naam;
        this.type = type;
    }

    /**
     * Zet de positie van de persoon (bijv. bij spawn)
     */
    public void setStartPositie(double startX, double startY) {
        this.x = startX;
        this.y = startY;
        this.destX = startX;
        this.destY = startY;
        System.out.println("[Spawn] " + getNaam() + " (" + type + ") geplaatst op (" + x + ", " + y + ")");
    }

    /**
     * DIT IS DE FIX VOOR DE LIFT:
     * Omdat deze methode nu in Persoon staat, kan de Lift-klasse
     * p.setLiftPosition(...) aanroepen zonder foutmeldingen!
     */
    public void setLiftPosition(double lx, double ly) {
        this.x = lx;
        this.y = ly;
        // Zorg dat het doel van de persoon meebeweegt zodat ze niet
        // uit de lift proberen te rennen terwijl deze beweegt.
        this.destX = lx;
        this.destY = ly;
    }

    // Standaard Getters
    public int getId() { return id; }
    public String getNaam() { return naam; }
    public String getType() { return type; }
    public double getX() { return x; }
    public double getY() { return y; }
    public String getHuidigeActiviteit() { return huidigeActiviteit; }

    // Standaard Setters (handig voor algemeen gebruik)
    public void setX(double x) { this.x = x; }
    public void setY(double y) { this.y = y; }
    public void setHuidigeActiviteit(String activiteit) { this.huidigeActiviteit = activiteit; }

    @Override
    public abstract void onTick();
}

