package model;

import java.awt.Color;
import java.util.ArrayList;
import java.util.List;

public class Schoonmaker extends Persoon {
    private static final double SPEED = 0.15; // Iets rustiger voor vloeiende animatie
    private static final double LIFT_X = 1.5;
    private static final int SCHOONMAAK_DUUR = 100;

    private Hotel hotel;
    private Lift lift;
    private Kamer huidigKamer;
    private int schoonmaakTimer = 0;
    private boolean inLift = false;
    private int doelVerdieping;

    private enum State { VRIJ, NAAR_DOEL, SCHOONMAKEN, IN_LIFT }
    private State state = State.VRIJ;

    public Schoonmaker(String naam, int startX, int startY) {
        super(naam, "Schoonmaker");

        // FORCEER STARTPOSITIE NAAR OPSLAG (1 grid linksboven van Position 8,6 = Position 7,5)
        // We negeren startX en startY die vanuit de simulator komen.
        this.x = 7.5;
        this.y = 5.5;

        System.out.println("[Schoonmaker] " + naam + " is in de Opslag (7,5)");
    }

    @Override
    public void onTick() {
        // Update activiteit label
        updateActiviteitLabel();

        if (inLift) {
            handleLiftMovement();
            return;
        }

        // ... existing code...
        Kamer viezeKamer = zoekViezeKamer();

        if (viezeKamer == null) {
            if (state == State.NAAR_DOEL) {
                state = State.VRIJ;
                huidigKamer = null;
            }

            if (Math.abs(x - 7.5) > 0.1) {
                x += (x < 7.5) ? SPEED : -SPEED;
            } else if (Math.abs(y - 5.5) > 0.1) {
                y += (y < 5.5) ? SPEED : -SPEED;
            } else {
                state = State.VRIJ;
            }
            return;
        }

        double targetX = viezeKamer.getArea().getX() + 0.5;
        double targetY = viezeKamer.getArea().getY() + 0.5;

        if (state == State.SCHOONMAKEN) {
            werkAanKamer();
        } else {
            beweeg(targetX, targetY, viezeKamer);
        }
    }

    private void updateActiviteitLabel() {
        if (inLift) {
            setHuidigeActiviteit(" In Lift");
        } else {
            switch (state) {
                case VRIJ:
                    setHuidigeActiviteit("⏳ Idle");
                    break;
                case NAAR_DOEL:
                    setHuidigeActiviteit(" Naar Kamer");
                    break;
                case SCHOONMAKEN:
                    setHuidigeActiviteit(" Schoon");
                    break;
                case IN_LIFT:
                    setHuidigeActiviteit(" In Lift");
                    break;
                default:
                    setHuidigeActiviteit("");
            }
        }
    }

    private void beweeg(double tx, double ty, Kamer doelKamer) {
        // Check: Is the target room still dirty? If not, abort and go back to storage
        if (doelKamer.getStatus() != Kamer.KamerStatus.SCHOONMAKEN) {
            state = State.VRIJ;
            huidigKamer = null;
            return;  // Abort, go back to storage in next tick
        }

        // Verdieping check
        if ((int)y != (int)ty) {
            // Ga naar lift
            if (Math.abs(x - LIFT_X) > 0.1) {
                x += (x < LIFT_X) ? SPEED : -SPEED;
            } else {
                stapInLift((int)ty);
            }
        } else {
            // Op de juiste verdieping, loop naar X
            if (Math.abs(x - tx) > 0.1) {
                x += (x < tx) ? SPEED : -SPEED;
            } else {
                // Gearriveerd
                if (doelKamer != null && doelKamer.getStatus() == Kamer.KamerStatus.SCHOONMAKEN) {
                    this.huidigKamer = doelKamer;
                    this.state = State.SCHOONMAKEN;
                    this.schoonmaakTimer = SCHOONMAAK_DUUR;
                } else {
                    this.state = State.VRIJ;
                }
            }
        }
    }

    private void werkAanKamer() {
        schoonmaakTimer--;
        if (schoonmaakTimer <= 0) {
            huidigKamer.setStatus(Kamer.KamerStatus.VRIJ);
            System.out.println("[Schoonmaker] Kamer " + huidigKamer.getKamernummer() + " is klaar.");
            huidigKamer = null;
            state = State.VRIJ; // Dit triggert de loop naar de opslag in de volgende tick
        }
    }

    private void stapInLift(int doelVerdieping) {
        if (lift != null && Math.abs(lift.getY() - y) < 0.3 && lift.isIdle()) {
            if (lift.voegGastToe(this, doelVerdieping)) {
                this.inLift = true;
                this.doelVerdieping = doelVerdieping;
                this.state = State.IN_LIFT;
            }
        }
    }

    private void handleLiftMovement() {
        this.x = lift.getX();
        this.y = lift.getY();

        // Exit lift when at the correct floor and lift is idle
        if ((int)lift.getY() == doelVerdieping && lift.isIdle()) {
            // Double-check: Is there still a dirty room to clean?
            Kamer viezeKamer = zoekViezeKamer();
            if (viezeKamer == null) {
                // No more dirty rooms, abort mission and go back to storage
                lift.verwijderGast(this);
                this.inLift = false;
                this.y = doelVerdieping + 0.5;
                this.state = State.VRIJ;
                return;
            }

            lift.verwijderGast(this);
            this.inLift = false;
            this.y = doelVerdieping + 0.5;
            this.state = State.NAAR_DOEL;
        }
    }

    private Kamer zoekViezeKamer() {
        if (hotel == null) return null;
        for (Kamer k : hotel.getKamers()) {
            if (k.getStatus() == Kamer.KamerStatus.SCHOONMAKEN) return k;
        }
        return null;
    }

    // Setters voor initialisatie
    public void setHotel(Hotel h) { this.hotel = h; }
    public void setLift(Lift l) { this.lift = l; }
    public void setGridBounds(int mx, int my) { } // Niet meer nodig met vaste opslag

    // Getters voor tekenen
    public double getX() { return x; }
    public double getY() { return y; }
    public Color getKleur() { return Color.GRAY; }
}

package model;

import java.awt.Color;
import java.util.ArrayList;
import java.util.List;

public class Schoonmaker extends Persoon {
    private static final double SPEED = 0.15; // Iets rustiger voor vloeiende animatie
    private static final double LIFT_X = 1.5;
    private static final int SCHOONMAAK_DUUR = 100;

    private Hotel hotel;
    private Lift lift;
    private Kamer huidigKamer;
    private int schoonmaakTimer = 0;
    private boolean inLift = false;
    private int doelVerdieping;
    private int maxY = 6;  // Default lobby floor (can be overridden)

    private enum State { VRIJ, NAAR_DOEL, SCHOONMAKEN, IN_LIFT, EVACUATIE }
    private State state = State.VRIJ;

    public Schoonmaker(String naam, int startX, int startY) {
        super(naam, "Schoonmaker");

        // FORCEER STARTPOSITIE NAAR OPSLAG (1 grid linksboven van Position 8,6 = Position 7,5)
        // We negeren startX en startY die vanuit de simulator komen.
        this.x = 7.5;
        this.y = 5.5;

        System.out.println("[Schoonmaker] " + naam + " is in de Opslag (7,5)");
    }

    @Override
    public void onTick() {
        // Update activiteit label
        updateActiviteitLabel();

        // Handle fire alarm evacuation
        if (fireAlarmActive && !evacuatieBegonnen) {
            startEvacuatie();
        }

        // Handle when fire alarm is cleared while in evacuation
        if (!fireAlarmActive && evacuatieBegonnen) {
            if (state == State.EVACUATIE) {
                // Go back to normal
                evacuatieBegonnen = false;
                state = State.VRIJ;
                setHuidigeActiviteit("⏳ Idle");
                // Reset position to storage
                x = 7.5;
                y = 5.5;
            }
        }

        if (inLift) {
            handleLiftMovement();
            return;
        }

        // If currently evacuating, handle that
        if (state == State.EVACUATIE) {
            handleEvacuatie();
            return;
        }

        // ... existing code...
        Kamer viezeKamer = zoekViezeKamer();

        if (viezeKamer == null) {
            if (state == State.NAAR_DOEL) {
                state = State.VRIJ;
                huidigKamer = null;
            }

            if (Math.abs(x - 7.5) > 0.1) {
                x += (x < 7.5) ? SPEED : -SPEED;
            } else if (Math.abs(y - 5.5) > 0.1) {
                y += (y < 5.5) ? SPEED : -SPEED;
            } else {
                state = State.VRIJ;
            }
            return;
        }

        double targetX = viezeKamer.getArea().getX() + 0.5;
        double targetY = viezeKamer.getArea().getY() + 0.5;

        if (state == State.SCHOONMAKEN) {
            werkAanKamer();
        } else {
            beweeg(targetX, targetY, viezeKamer);
        }
    }

    private void updateActiviteitLabel() {
        if (inLift) {
            setHuidigeActiviteit(" In Lift");
        } else {
            switch (state) {
                case VRIJ:
                    setHuidigeActiviteit("⏳ Idle");
                    break;
                case NAAR_DOEL:
                    setHuidigeActiviteit(" Naar Kamer");
                    break;
                case SCHOONMAKEN:
                    setHuidigeActiviteit(" Schoon");
                    break;
                case IN_LIFT:
                    setHuidigeActiviteit(" In Lift");
                    break;
                case EVACUATIE:
                    setHuidigeActiviteit(" EVACUATIE!");
                    break;
                default:
                    setHuidigeActiviteit("");
            }
        }
    }

    private void beweeg(double tx, double ty, Kamer doelKamer) {
        // Check: Is the target room still dirty? If not, abort and go back to storage
        if (doelKamer.getStatus() != Kamer.KamerStatus.SCHOONMAKEN) {
            state = State.VRIJ;
            huidigKamer = null;
            return;  // Abort, go back to storage in next tick
        }

        // Verdieping check
        if ((int)y != (int)ty) {
            // Ga naar lift
            if (Math.abs(x - LIFT_X) > 0.1) {
                x += (x < LIFT_X) ? SPEED : -SPEED;
            } else {
                stapInLift((int)ty);
            }
        } else {
            // Op de juiste verdieping, loop naar X
            if (Math.abs(x - tx) > 0.1) {
                x += (x < tx) ? SPEED : -SPEED;
            } else {
                // Gearriveerd
                if (doelKamer != null && doelKamer.getStatus() == Kamer.KamerStatus.SCHOONMAKEN) {
                    this.huidigKamer = doelKamer;
                    this.state = State.SCHOONMAKEN;
                    this.schoonmaakTimer = SCHOONMAAK_DUUR;
                } else {
                    this.state = State.VRIJ;
                }
            }
        }
    }

    private void werkAanKamer() {
        schoonmaakTimer--;
        if (schoonmaakTimer <= 0) {
            huidigKamer.setStatus(Kamer.KamerStatus.VRIJ);
            System.out.println("[Schoonmaker] Kamer " + huidigKamer.getKamernummer() + " is klaar.");
            huidigKamer = null;
            state = State.VRIJ; // Dit triggert de loop naar de opslag in de volgende tick
        }
    }

    private void stapInLift(int doelVerdieping) {
        if (lift != null && Math.abs(lift.getY() - y) < 0.3 && lift.isIdle()) {
            if (lift.voegGastToe(this, doelVerdieping)) {
                this.inLift = true;
                this.doelVerdieping = doelVerdieping;
                this.state = State.IN_LIFT;
            }
        }
    }

    private void handleLiftMovement() {
        this.x = lift.getX();
        this.y = lift.getY();

        // Exit lift when at the correct floor and lift is idle
        if ((int)lift.getY() == doelVerdieping && lift.isIdle()) {
            // Double-check: Is there still a dirty room to clean?
            Kamer viezeKamer = zoekViezeKamer();
            if (viezeKamer == null) {
                // No more dirty rooms, abort mission and go back to storage
                lift.verwijderGast(this);
                this.inLift = false;
                this.y = doelVerdieping + 0.5;
                this.state = State.VRIJ;
                return;
            }

            lift.verwijderGast(this);
            this.inLift = false;
            this.y = doelVerdieping + 0.5;
            this.state = State.NAAR_DOEL;
        }
    }

    private Kamer zoekViezeKamer() {
        if (hotel == null) return null;
        for (Kamer k : hotel.getKamers()) {
            if (k.getStatus() == Kamer.KamerStatus.SCHOONMAKEN) return k;
        }
        return null;
    }

    /**
     * Wordt aangeroepen bij brandalarm - interrupt alle activiteiten
     */
    private void startEvacuatie() {
        evacuatieBegonnen = true;

        // Leave cleaner immediately
        if (inLift && lift != null) {
            lift.verwijderGast(this);
            inLift = false;
        }

        huidigKamer = null;
        state = State.EVACUATIE;
        System.out.println("[FireAlarm]  " + getNaam() + " begint evacuatie naar lobby!");
    }

    /**
     * Schoonmaker evacuation to lobby via stairs
     */
    private void handleEvacuatie() {
        double lobbyX = 1.5;
        int lobbyY = maxY - 1;  // Dynamic lobby floor based on hotel size

        // Go to stairs if not on lobby floor
        if ((int)y != lobbyY) {
            double stairX = 8.5;
            if (Math.abs(x - stairX) > SPEED) {
                x += (x < stairX) ? SPEED : -SPEED;
            } else {
                // Move up stairs
                if (y < lobbyY) {
                    y += SPEED;
                } else if (y > lobbyY) {
                    y -= SPEED;
                }
            }
        } else {
            // On lobby floor, move to lobby position
            double dx = lobbyX - x;
            if (Math.abs(dx) < SPEED) {
                x = lobbyX;
                // Reached lobby - exit building
                state = State.VRIJ;
                setHuidigeActiviteit(" Verlaten gebouw");
                // Move outside
                x = -1.5; // Stay just outside
            } else {
                x += (dx > 0) ? SPEED : -SPEED;
            }
        }
    }

    // Setters voor initialisatie
    public void setHotel(Hotel h) { this.hotel = h; }
    public void setLift(Lift l) { this.lift = l; }
    public void setGridBounds(int mx, int my) { this.maxY = my; }  // Store hotel height

    // Getters voor tekenen
    public double getX() { return x; }
    public double getY() { return y; }
    public Color getKleur() { return Color.GRAY; }
}

package model;

import model.TickListener;
import ui.HotelPanel;
import java.util.List;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.Map;

public class Simulator {
    private boolean running = false;
    private Hotel hotel;
    private HotelPanel hotelPanel;
    private SimulationClock clock;
    private HTEClock hteClock;
    private Lift lift;
    private Area lobbyArea;
    private int lastGuestSpawnTime = 0;
    private Map<String, Integer> guestCheckInTime = new HashMap<>();  // Track check-in times

    public Simulator(Hotel hotel, HotelPanel hotelPanel) {
        this.hotel = hotel;
        this.hotelPanel = hotelPanel;
        this.clock = new SimulationClock(100);
        this.hteClock = new HTEClock();

        initialiseerLift();
        initialiseerPersonen();
    }

    private void initialiseerLift() {
        for (Area a : hotel.getAreas()) {
            String type = a.getAreaType();
            if (type != null && (type.equalsIgnoreCase("Schacht") ||
                    type.equalsIgnoreCase("Lift") ||
                    type.equalsIgnoreCase("Elevator"))) {

                double liftX = (a.getX() - 1) + 0.5;
                double liftY = (a.getY() + a.getHoogte() - 2) + 0.5;
                int minY = a.getY() - 1;
                int maxY = a.getY() + a.getHoogte() - 2;

                this.lift = new Lift(liftX, liftY, minY, maxY);
                hteClock.addListener(this.lift);

                System.out.println("[Simulator] Lift succesvol geïnitialiseerd.");
                return;
            }
        }
    }

    private void initialiseerPersonen() {
        Area lobbyArea = hotel.getAreas().stream()
                .filter(a -> a.getAreaType() != null && a.getAreaType().equalsIgnoreCase("Lobby"))
                .findFirst().orElse(null);

        Area opslagArea = hotel.getAreas().stream()
                .filter(a -> a.getAreaType() != null && (a.getAreaType().equalsIgnoreCase("Storage") || a.getAreaType().equalsIgnoreCase("Opslag")))
                .findFirst().orElse(null);

        // Store lobby reference for dynamic spawning
        this.lobbyArea = lobbyArea;

        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof TickListener) {
                hteClock.addListener((TickListener) p);
            }

            // --- GAST INITIALISATIE ---
            if (p instanceof Gast) {
                Gast g = (Gast) p;
                g.setLift(lift);
                g.setHotel(hotel);
                g.setGridBounds(hotel.getBreedte(), hotel.getHoogte());

                if (lobbyArea != null) {
                    // Spawn at x = -1.0 outside the hotel
                    double startX = -1.0;
                    double startY = (lobbyArea.getY() - 1) + 0.5;
                    g.setStartPositie(startX, startY);
                }
            }

            // --- SCHOONMAKER INITIALISATIE ---
            if (p instanceof Schoonmaker) {
                Schoonmaker s = (Schoonmaker) p;
                s.setLift(lift);
                s.setHotel(hotel);
                s.setGridBounds(hotel.getBreedte(), hotel.getHoogte());

                if (opslagArea != null) {
                    // Keep cleaners in storage (1 grid linksboven van opslag: Position 7, 5)
                    double startX = opslagArea.getX() - 0.5;
                    double startY = opslagArea.getY() - 0.5;
                    s.setStartPositie(startX, startY);
                }
            }
        }
    }

    public void tick() {
        if (running && clock.tick()) {
            hteClock.tick();

            // Remove guests that have left the hotel (x < -1)
            hotel.getPersonen().removeIf(p -> p instanceof Gast && p.getX() < -1.0);

            // Auto-check in waiting guests
            autoCheckInGuests();

            // Auto-checkout guests after 300 ticks in room
            autoCheckoutGuests();

            // Periodically spawn new guests (every 100 ticks instead of 200)
            lastGuestSpawnTime++;
            if (lastGuestSpawnTime >= 100 && hasAvailableRoom()) {
                spawnNewGuest();
                lastGuestSpawnTime = 0;
            }
        }
        hotelPanel.repaint();
    }

    private void autoCheckInGuests() {
        try {
            for (Persoon p : new ArrayList<>(hotel.getPersonen())) {
                if (p instanceof Gast) {
                    Gast gast = (Gast) p;
                    // If guest is in lobby and not checked in yet
                    if (gast.getHuidigKamer() == null && (int)gast.getY() == 6 && gast.getX() > 1.0) {
                        // Try to check in to available room
                        Kamer k = hotel.zoekVrijeKamer("Luxe");
                        if (k == null) k = hotel.zoekVrijeKamer("Standaard");
                        if (k == null) k = hotel.zoekVrijeKamer("Budget");

                        if (k != null) {
                            gast.checkinKamer(k);
                            guestCheckInTime.put(gast.getNaam(), 0);  // Start timer
                            System.out.println("[AUTO-CHECKIN] " + gast.getNaam() + " checked in to room " + k.getKamernummer());
                        }
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("[autoCheckInGuests] Error: " + e.getMessage());
        }
    }

    private void autoCheckoutGuests() {
        try {
            for (Persoon p : new ArrayList<>(hotel.getPersonen())) {
                if (p instanceof Gast) {
                    Gast gast = (Gast) p;
                    if (gast.getHuidigKamer() != null && guestCheckInTime.containsKey(gast.getNaam())) {
                        // Increment stay time
                        int stayTime = guestCheckInTime.get(gast.getNaam());
                        stayTime++;
                        guestCheckInTime.put(gast.getNaam(), stayTime);

                        // Auto-checkout after 300 ticks
                        if (stayTime >= 300) {
                            gast.checkoutKamer();
                            guestCheckInTime.remove(gast.getNaam());
                            System.out.println("[AUTO-CHECKOUT] " + gast.getNaam() + " checked out");
                        }
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("[autoCheckoutGuests] Error: " + e.getMessage());
        }
    }

    private boolean hasAvailableRoom() {
        for (Kamer k : hotel.getKamers()) {
            if (k.getStatus() == Kamer.KamerStatus.VRIJ) return true;
        }
        return false;
    }

    private void spawnNewGuest() {
        if (lobbyArea == null) return;

        String[] firstNames = {"Emma", "Liam", "Olivia", "Noah", "Ava", "Elijah", "Sophia", "Mason"};
        String[] types = {"Luxe", "Standaard", "Budget"};

        String name = firstNames[(int)(Math.random() * firstNames.length)];
        String type = types[(int)(Math.random() * types.length)];

        Gast newGuest = new Gast(name, -1, 0);
        newGuest.setLift(lift);
        newGuest.setHotel(hotel);
        newGuest.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        newGuest.setStartPositie(-1.0, (lobbyArea.getY() - 1) + 0.5);

        hteClock.addListener(newGuest);
        hotel.addPersoon(newGuest);

        System.out.println("[Simulator] Nieuwe gast '" + name + "' komt aan (kamertype: " + type + ")");
    }

    public void start() { this.running = true; clock.start(); }
    public void pause() { this.running = false; clock.stop(); }
    public boolean isRunning() { return running; }
    public SimulationClock getClock() { return clock; }
    public Lift getLift() { return lift; }
    public void resetClock() { this.clock.reset(); }

    public boolean gastCheckin(String naam, String type) {
        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof Gast && p.getNaam().equals(naam)) {
                Kamer k = hotel.zoekVrijeKamer(type);
                if (k != null) return ((Gast) p).checkinKamer(k);
            }
        }
        return false;
    }

    public void gastCheckout(String naam) {
        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof Gast && p.getNaam().equals(naam)) {
                ((Gast) p).checkoutKamer();
            }
        }
    }
}

package model;

import model.TickListener;
import ui.HotelPanel;
import java.util.List;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.Map;

public class Simulator {
    private boolean running = false;
    private Hotel hotel;
    private HotelPanel hotelPanel;
    private SimulationClock clock;
    private HTEClock hteClock;
    private Lift lift;
    private Area lobbyArea;
    private int lastGuestSpawnTime = 0;
    private Map<String, Integer> guestCheckInTime = new HashMap<>();  // Track check-in times

    public Simulator(Hotel hotel, HotelPanel hotelPanel) {
        this.hotel = hotel;
        this.hotelPanel = hotelPanel;
        this.clock = new SimulationClock(100);
        this.hteClock = new HTEClock();

        initialiseerLift();
        initialiseerPersonen();
    }

    private void initialiseerLift() {
        for (Area a : hotel.getAreas()) {
            String type = a.getAreaType();
            if (type != null && (type.equalsIgnoreCase("Schacht") ||
                    type.equalsIgnoreCase("Lift") ||
                    type.equalsIgnoreCase("Elevator"))) {

                double liftX = (a.getX() - 1) + 0.5;
                double liftY = (a.getY() + a.getHoogte() - 2) + 0.5;
                int minY = a.getY() - 1;
                int maxY = a.getY() + a.getHoogte() - 2;

                this.lift = new Lift(liftX, liftY, minY, maxY);
                hteClock.addListener(this.lift);

                System.out.println("[Simulator] Lift succesvol geïnitialiseerd.");
                return;
            }
        }
    }

    private void initialiseerPersonen() {
        Area lobbyArea = hotel.getAreas().stream()
                .filter(a -> a.getAreaType() != null && a.getAreaType().equalsIgnoreCase("Lobby"))
                .findFirst().orElse(null);

        Area opslagArea = hotel.getAreas().stream()
                .filter(a -> a.getAreaType() != null && (a.getAreaType().equalsIgnoreCase("Storage") || a.getAreaType().equalsIgnoreCase("Opslag")))
                .findFirst().orElse(null);

        // Store lobby reference for dynamic spawning
        this.lobbyArea = lobbyArea;

        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof TickListener) {
                hteClock.addListener((TickListener) p);
            }

            // --- GAST INITIALISATIE ---
            if (p instanceof Gast) {
                Gast g = (Gast) p;
                g.setLift(lift);
                g.setHotel(hotel);
                g.setGridBounds(hotel.getBreedte(), hotel.getHoogte());

                if (lobbyArea != null) {
                    // Spawn at x = -1.0 outside the hotel
                    double startX = -1.0;
                    double startY = (lobbyArea.getY() - 1) + 0.5;
                    g.setStartPositie(startX, startY);
                }
            }

            // --- SCHOONMAKER INITIALISATIE ---
            if (p instanceof Schoonmaker) {
                Schoonmaker s = (Schoonmaker) p;
                s.setLift(lift);
                s.setHotel(hotel);
                s.setGridBounds(hotel.getBreedte(), hotel.getHoogte());

                if (opslagArea != null) {
                    // Keep cleaners in storage (1 grid linksboven van opslag: Position 7, 5)
                    double startX = opslagArea.getX() - 0.5;
                    double startY = opslagArea.getY() - 0.5;
                    s.setStartPositie(startX, startY);
                }
            }
        }
    }

    public void tick() {
        if (running && clock.tick()) {
            hteClock.tick();

            // Remove only guests that have gone way outside (x < -2)
            // Guests at x = -1.5 are still outside but can return
            hotel.getPersonen().removeIf(p -> (p instanceof Gast || p instanceof Schoonmaker) && p.getX() < -2.0);

            // Auto-check in waiting guests
            autoCheckInGuests();

            // Auto-checkout guests after 300 ticks in room
            autoCheckoutGuests();

            // Periodically spawn new guests (every 100 ticks instead of 200)
            lastGuestSpawnTime++;
            if (lastGuestSpawnTime >= 100 && hasAvailableRoom()) {
                spawnNewGuest();
                lastGuestSpawnTime = 0;
            }
        }
        hotelPanel.repaint();
    }

    private void autoCheckInGuests() {
        // Block check-in during fire alarm
        if (lift != null && lift.isFireAlarmActive()) {
            return;  // No check-ins during evacuation!
        }

        try {
            for (Persoon p : new ArrayList<>(hotel.getPersonen())) {
                if (p instanceof Gast) {
                    Gast gast = (Gast) p;
                    // If guest is in lobby and not checked in yet
                    if (gast.getHuidigKamer() == null && (int)gast.getY() == 6 && gast.getX() > 1.0) {
                        // Try to check in to available room
                        Kamer k = hotel.zoekVrijeKamer("Luxe");
                        if (k == null) k = hotel.zoekVrijeKamer("Standaard");
                        if (k == null) k = hotel.zoekVrijeKamer("Budget");

                        if (k != null) {
                            gast.checkinKamer(k);
                            guestCheckInTime.put(gast.getNaam(), 0);  // Start timer
                            System.out.println("[AUTO-CHECKIN] " + gast.getNaam() + " checked in to room " + k.getKamernummer());
                        }
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("[autoCheckInGuests] Error: " + e.getMessage());
        }
    }

    private void autoCheckoutGuests() {
        // Block checkout during fire alarm
        if (lift != null && lift.isFireAlarmActive()) {
            return;  // No checkouts during evacuation!
        }

        try {
            for (Persoon p : new ArrayList<>(hotel.getPersonen())) {
                if (p instanceof Gast) {
                    Gast gast = (Gast) p;
                    if (gast.getHuidigKamer() != null && guestCheckInTime.containsKey(gast.getNaam())) {
                        // Increment stay time
                        int stayTime = guestCheckInTime.get(gast.getNaam());
                        stayTime++;
                        guestCheckInTime.put(gast.getNaam(), stayTime);

                        // Auto-checkout after 300 ticks
                        if (stayTime >= 300) {
                            gast.checkoutKamer();
                            guestCheckInTime.remove(gast.getNaam());
                            System.out.println("[AUTO-CHECKOUT] " + gast.getNaam() + " checked out");
                        }
                    }
                }
            }
        } catch (Exception e) {
            System.err.println("[autoCheckoutGuests] Error: " + e.getMessage());
        }
    }

    private boolean hasAvailableRoom() {
        for (Kamer k : hotel.getKamers()) {
            if (k.getStatus() == Kamer.KamerStatus.VRIJ) return true;
        }
        return false;
    }

    private void spawnNewGuest() {
        if (lobbyArea == null) return;

        String[] firstNames = {"Emma", "Liam", "Olivia", "Noah", "Ava", "Elijah", "Sophia", "Mason"};
        String[] types = {"Luxe", "Standaard", "Budget"};

        String name = firstNames[(int)(Math.random() * firstNames.length)];
        String type = types[(int)(Math.random() * types.length)];

        Gast newGuest = new Gast(name, -1, 0);
        newGuest.setLift(lift);
        newGuest.setHotel(hotel);
        newGuest.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        newGuest.setStartPositie(-1.0, (lobbyArea.getY() - 1) + 0.5);

        hteClock.addListener(newGuest);
        hotel.addPersoon(newGuest);

        System.out.println("[Simulator] Nieuwe gast '" + name + "' komt aan (kamertype: " + type + ")");
    }

    public void start() { this.running = true; clock.start(); }
    public void pause() { this.running = false; clock.stop(); }
    public boolean isRunning() { return running; }
    public SimulationClock getClock() { return clock; }
    public Lift getLift() { return lift; }
    public void resetClock() { this.clock.reset(); }

    public boolean gastCheckin(String naam, String type) {
        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof Gast && p.getNaam().equals(naam)) {
                Kamer k = hotel.zoekVrijeKamer(type);
                if (k != null) return ((Gast) p).checkinKamer(k);
            }
        }
        return false;
    }

    public void gastCheckout(String naam) {
        for (Persoon p : hotel.getPersonen()) {
            if (p instanceof Gast && p.getNaam().equals(naam)) {
                ((Gast) p).checkoutKamer();
            }
        }
    }

    /**
     * Triggers a fire alarm - all personen evacuate to lobby via stairs
     * US4.3: Brandalarm feature
     */
    public void triggerFireAlarm() {
        System.out.println("\n" + "=".repeat(60));
        System.out.println("    FIRE ALARM ACTIVATED - EVACUATIE BEGONNEN    ");
        System.out.println("=".repeat(60) + "\n");

        // Disable lift
        if (lift != null) {
            lift.activeerFireAlarm();
        }

        // Alert all personen to evacuate
        for (Persoon p : hotel.getPersonen()) {
            p.activeerFireAlarm();
        }
    }

    /**
     * Clears the fire alarm - simulation returns to normal
     * US4.3: Brandalarm feature
     */
    public void clearFireAlarm() {
        System.out.println("\n" + "=".repeat(60));
        System.out.println("✓ ✓ ✓  FIRE ALARM CLEARED - EVACUATION COMPLETE  ✓ ✓ ✓");
        System.out.println("=".repeat(60) + "\n");

        // Re-enable lift
        if (lift != null) {
            lift.deactiveerFireAlarm();
        }

        // Clear alarm for all personen
        for (Persoon p : hotel.getPersonen()) {
            p.deactiveerFireAlarm();
        }
    }
}

package ui;

import model.Area;
import model.Hotel;
import model.Gast;
import model.Persoon;
import model.Lift;
import model.Schoonmaker;
import javax.swing.*;
import javax.swing.event.MouseInputListener;
import java.awt.*;
import java.awt.event.MouseEvent;
import java.util.List;

/**
 * Dit paneel is verantwoordelijk voor het visueel weergeven van het hotel.
 * US4.4: Grafische weergave implementatie voor het volgen van de simulatie.
 * US2.1: Klik op Lobby om gastenoverzicht te openen
 */
public class HotelPanel extends JPanel implements MouseInputListener {

    private Hotel hotel;
    private Lift lift;  // Referentie naar de lift om deze te tekenen

    private final int VAKJE_GROOTTE = 50;

    // status van simulatie (optioneel)
    private boolean running = true;

    // US2.1: Callback voor lobby clicks
    private Runnable onLobbyClick;

    public HotelPanel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();

        // US2.1: Voeg mouse listener toe
        addMouseListener(this);
        setFocusable(true);
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
        repaint();
    }

    public void setLift(Lift lift) {
        this.lift = lift;
    }

    // Simulator kan dit gebruiken
    public void setRunning(boolean running) {
        this.running = running;
    }

    // US2.1: Stel callback in voor lobby clicks
    public void setOnLobbyClick(Runnable callback) {
        this.onLobbyClick = callback;
    }

    private void updateDimensions() {
        if (hotel == null) return;

        int breedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        this.setPreferredSize(new Dimension(breedte, hoogte));
        revalidate(); // belangrijk voor UI refresh
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        if (hotel == null) return;

        // Achtergrond (vloer)
        g.setColor(Color.WHITE);
        g.fillRect(0, 0, getWidth(), getHeight());

        // Bereken offsets om hotel in het midden te centreren
        int hotelBreedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hotelHoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        int offsetX = (getWidth() - hotelBreedte) / 2;
        int offsetY = (getHeight() - hotelHoogte) / 2;

        // === US4.4: HULPLIJNEN (GRID) ===
        // Teken een licht grijs grid zodat de gebruiker de vakjes/afstanden ziet
        g.setColor(new Color(230, 230, 230));
        for (int i = 0; i <= hotel.getBreedte(); i++) {
            g.drawLine(offsetX + i * VAKJE_GROOTTE, offsetY, offsetX + i * VAKJE_GROOTTE, offsetY + hotelHoogte);
        }
        for (int j = 0; j <= hotel.getHoogte(); j++) {
            g.drawLine(offsetX, offsetY + j * VAKJE_GROOTTE, offsetX + hotelBreedte, offsetY + j * VAKJE_GROOTTE);
        }

        // Areas tekenen
        List<Area> areas = hotel.getAreas();
        for (Area area : areas) {
            // SKIP: De 1x1 Lift area - deze wordt dynamisch getekend!
            if (area.getAreaType().equals("Lift")) {
                continue;  // Teken NIET op vaste positie
            }

            int x = (area.getX() - 1) * VAKJE_GROOTTE + offsetX;
            int y = (area.getY() - 1) * VAKJE_GROOTTE + offsetY;

            int breedte = area.getBreedte() * VAKJE_GROOTTE;
            int hoogte = area.getHoogte() * VAKJE_GROOTTE;

            // Achtergrond kleur
            g.setColor(getKleur(area));
            g.fillRect(x, y, breedte, hoogte);

            // Rand
            g.setColor(Color.DARK_GRAY);
            Graphics2D g2 = (Graphics2D) g;
            g2.setStroke(new BasicStroke(2));
            g.drawRect(x, y, breedte, hoogte);
            g2.setStroke(new BasicStroke(1));

            // Label
            g.setColor(Color.BLACK);
            g.setFont(new Font("Arial", Font.BOLD, 12));
            String label = getLabel(area);
            FontMetrics fm = g.getFontMetrics();

            int textX = x + (breedte - fm.stringWidth(label)) / 2;
            int textY = y + (hoogte + fm.getAscent()) / 2 - 2;

            g.drawString(label, textX, textY);
        }

        // === TEKEN LIFT (BEWEGEND OBJECT) ===
        if (lift != null) {
            int liftX = (int)(lift.getX() * VAKJE_GROOTTE) + offsetX - VAKJE_GROOTTE/2;
            int liftY = (int)(lift.getY() * VAKJE_GROOTTE) + offsetY - VAKJE_GROOTTE/2;

            g.setColor(new Color(200, 100, 0));  // Oranje
            g.fillRect(liftX, liftY, VAKJE_GROOTTE, VAKJE_GROOTTE);

            g.setColor(Color.BLACK);
            Graphics2D g2d = (Graphics2D) g;
            g2d.setStroke(new BasicStroke(2));
            g.drawRect(liftX, liftY, VAKJE_GROOTTE, VAKJE_GROOTTE);

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            FontMetrics fm = g.getFontMetrics();
            int lx = liftX + (VAKJE_GROOTTE - fm.stringWidth("L")) / 2;
            int ly = liftY + (VAKJE_GROOTTE + fm.getAscent()) / 2 - 5;
            g.drawString("L", lx, ly);
        }

        // Teken alle personen
        for (Persoon persoon : hotel.getPersonen()) {
            if (persoon instanceof Gast) {
                Gast gast = (Gast) persoon;
                int px = (int)(gast.getX() * VAKJE_GROOTTE) + offsetX - 8;
                int py = (int)(gast.getY() * VAKJE_GROOTTE) + offsetY - 8;

                g.setColor(gast.getKleur());
                g.fillOval(px, py, 16, 16);

                g.setColor(new Color(
                        Math.max(0, gast.getKleur().getRed() - 80),
                        Math.max(0, gast.getKleur().getGreen() - 80),
                        Math.max(0, gast.getKleur().getBlue() - 80)
                ));
                g.drawOval(px, py, 16, 16);

                // Naam + activiteit boven de gast
                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.BOLD, 9));
                String label = gast.getNaam();
                if (!gast.getHuidigeActiviteit().isEmpty()) {
                    label += " " + gast.getHuidigeActiviteit();
                }
                g.drawString(label, px - 5, py - 5);
            } else if (persoon instanceof Schoonmaker) {
                Schoonmaker schoonmaker = (Schoonmaker) persoon;
                int px = (int)(schoonmaker.getX() * VAKJE_GROOTTE) + offsetX - 8;
                int py = (int)(schoonmaker.getY() * VAKJE_GROOTTE) + offsetY - 8;

                g.setColor(schoonmaker.getKleur());
                g.fillRect(px, py, 16, 16);

                g.setColor(Color.BLACK);
                g.drawRect(px, py, 16, 16);

                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.BOLD, 10));
                g.drawString("S", px + 5, py + 8);

                // Activiteit label voor schoonmaker
                String label = "CM";
                if (!schoonmaker.getHuidigeActiviteit().isEmpty()) {
                    label += " " + schoonmaker.getHuidigeActiviteit();
                }
                g.setFont(new Font("Arial", Font.PLAIN, 8));
                g.drawString(label, px - 5, py - 3);
            }
        }

        // === US4.4: LEGENDA TOEVOEGEN ===
        tekenLegenda(g);

        // toon status (pause/active)
        if (!running) {
            g.setColor(new Color(0, 0, 0, 150));
            g.fillRect(0, 0, getWidth(), getHeight());

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            g.drawString("PAUSED", getWidth() / 2 - 70, getHeight() / 2);
        }
    }

    /**
     * Hulpmethode voor US4.4: Tekent een legenda zodat de gebruiker de simulatie begrijpt.
     */
    private void tekenLegenda(Graphics g) {
        int lx = 10;
        int ly = getHeight() - 70;

        // Achtergrond legenda
        g.setColor(new Color(255, 255, 255, 220));
        g.fillRect(lx, ly, 130, 60);
        g.setColor(Color.BLACK);
        g.drawRect(lx, ly, 130, 60);

        g.setFont(new Font("Arial", Font.PLAIN, 11));

        // Gast
        g.setColor(Color.BLUE);
        g.fillOval(lx + 10, ly + 10, 10, 10);
        g.setColor(Color.BLACK);
        g.drawString("Gast", lx + 30, ly + 20);

        // Schoonmaker
        g.setColor(Color.DARK_GRAY);
        g.fillRect(lx + 10, ly + 25, 10, 10);
        g.setColor(Color.BLACK);
        g.drawString("Schoonmaker", lx + 30, ly + 35);

        // Lift
        g.setColor(new Color(200, 100, 0));
        g.fillRect(lx + 10, ly + 40, 10, 10);
        g.setColor(Color.BLACK);
        g.drawString("Lift", lx + 30, ly + 50);
    }

    // === US2.1: MOUSE EVENT HANDLERS ===

    /**
     * Detecteert of de gebruiker op een Lobby klikt
     */
    @Override
    public void mouseClicked(MouseEvent e) {
        if (hotel == null) return;

        // Bereken offsets
        int hotelBreedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hotelHoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        int offsetX = (getWidth() - hotelBreedte) / 2;
        int offsetY = (getHeight() - hotelHoogte) / 2;

        // Check welke area is geklikt
        int clickX = e.getX();
        int clickY = e.getY();

        for (Area area : hotel.getAreas()) {
            if ("Lobby".equals(area.getAreaType())) {
                int x = (area.getX() - 1) * VAKJE_GROOTTE + offsetX;
                int y = (area.getY() - 1) * VAKJE_GROOTTE + offsetY;
                int breedte = area.getBreedte() * VAKJE_GROOTTE;
                int hoogte = area.getHoogte() * VAKJE_GROOTTE;

                // Check of klik in Lobby gebied valt
                if (clickX >= x && clickX <= x + breedte &&
                    clickY >= y && clickY <= y + hoogte) {

                    System.out.println("[US2.1]  Lobby aangeklikt - Gastenoverzicht openen");

                    if (onLobbyClick != null) {
                        onLobbyClick.run();
                    }
                    return;
                }
            }
        }
    }

    @Override
    public void mousePressed(MouseEvent e) {}

    @Override
    public void mouseReleased(MouseEvent e) {}

    @Override
    public void mouseEntered(MouseEvent e) {}

    @Override
    public void mouseExited(MouseEvent e) {}

    @Override
    public void mouseDragged(MouseEvent e) {}

    @Override
    public void mouseMoved(MouseEvent e) {}

    private String getLabel(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                return area.getClassification() != null ?
                        area.getClassification().replace(" Star", "★") : "Kamer";
            case "Cinema": return "Bioscoop";
            case "Restaurant": return "Restaurant";
            case "Fitness": return "Fitness";
            case "Lobby": return "Lobby";
            case "Schacht": return "Schacht";
            case "Lift": return "Lift";
            case "Staircase": return "Trap";
            case "Storage": return "Opslag";
            default: return area.getAreaType();
        }
    }

    private Color getKleur(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                String c = area.getClassification();
                if (c == null) return new Color(200, 230, 255);
                if (c.contains("1")) return new Color(200, 230, 255);
                if (c.contains("2")) return new Color(150, 200, 255);
                if (c.contains("3")) return new Color(100, 170, 255);
                if (c.contains("4")) return new Color(50, 130, 255);
                if (c.contains("5")) return new Color(0, 80, 200);
                return new Color(200, 230, 255);
            case "Lobby": return new Color(255, 220, 50);
            case "Schacht": return new Color(220, 220, 220);
            case "Lift": return new Color(255, 150, 0);
            case "Staircase": return new Color(100, 200, 100);
            case "Restaurant": return new Color(255, 100, 100);
            case "Cinema": return new Color(200, 100, 200);
            case "Fitness": return new Color(100, 220, 180);
            case "Storage": return new Color(180, 140, 100);
            default: return Color.WHITE;
        }
    }
}

package ui;

import model.Area;
import model.Hotel;
import model.Gast;
import model.Persoon;
import model.Lift;
import model.Schoonmaker;
import model.Kamer;
import javax.swing.*;
import javax.swing.event.MouseInputListener;
import java.awt.*;
import java.awt.event.MouseEvent;
import java.util.List;

/**
 * Dit paneel is verantwoordelijk voor het visueel weergeven van het hotel.
 * US4.4: Grafische weergave implementatie voor het volgen van de simulatie.
 * US2.1: Klik op Lobby om gastenoverzicht te openen
 */
public class HotelPanel extends JPanel implements MouseInputListener {

    private Hotel hotel;
    private Lift lift;  // Referentie naar de lift om deze te tekenen

    private final int VAKJE_GROOTTE = 50;

    // status van simulatie (optioneel)
    private boolean running = true;

    // US2.1: Callback voor lobby clicks
    private Runnable onLobbyClick;

    // New: Callbacks voor kamer en persoon detail windows
    private java.util.function.Consumer<model.Kamer> onRoomClick;
    private java.util.function.Consumer<model.Persoon> onPersonClick;

    public HotelPanel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();

        // US2.1: Voeg mouse listener toe
        addMouseListener(this);
        setFocusable(true);
    }

    public void setHotel(Hotel hotel) {
        this.hotel = hotel;
        updateDimensions();
        repaint();
    }

    public void setLift(Lift lift) {
        this.lift = lift;
    }

    // Simulator kan dit gebruiken
    public void setRunning(boolean running) {
        this.running = running;
    }

    // US2.1: Stel callback in voor lobby clicks
    public void setOnLobbyClick(Runnable callback) {
        this.onLobbyClick = callback;
    }

    // New: Stel callbacks in voor kamer en persoon details
    public void setOnRoomClick(java.util.function.Consumer<model.Kamer> callback) {
        this.onRoomClick = callback;
    }

    public void setOnPersonClick(java.util.function.Consumer<model.Persoon> callback) {
        this.onPersonClick = callback;
    }

    private void updateDimensions() {
        if (hotel == null) return;

        int breedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        this.setPreferredSize(new Dimension(breedte, hoogte));
        revalidate(); // belangrijk voor UI refresh
    }

    @Override
    protected void paintComponent(Graphics g) {
        super.paintComponent(g);

        if (hotel == null) return;

        // Achtergrond (vloer)
        g.setColor(Color.WHITE);
        g.fillRect(0, 0, getWidth(), getHeight());

        // Bereken offsets om hotel in het midden te centreren
        int hotelBreedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hotelHoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        int offsetX = (getWidth() - hotelBreedte) / 2;
        int offsetY = (getHeight() - hotelHoogte) / 2;

        // === US4.4: HULPLIJNEN (GRID) ===
        // Teken een licht grijs grid zodat de gebruiker de vakjes/afstanden ziet
        g.setColor(new Color(230, 230, 230));
        for (int i = 0; i <= hotel.getBreedte(); i++) {
            g.drawLine(offsetX + i * VAKJE_GROOTTE, offsetY, offsetX + i * VAKJE_GROOTTE, offsetY + hotelHoogte);
        }
        for (int j = 0; j <= hotel.getHoogte(); j++) {
            g.drawLine(offsetX, offsetY + j * VAKJE_GROOTTE, offsetX + hotelBreedte, offsetY + j * VAKJE_GROOTTE);
        }

        // Areas tekenen
        List<Area> areas = hotel.getAreas();
        for (Area area : areas) {
            // SKIP: De 1x1 Lift area - deze wordt dynamisch getekend!
            if (area.getAreaType().equals("Lift")) {
                continue;  // Teken NIET op vaste positie
            }

            int x = (area.getX() - 1) * VAKJE_GROOTTE + offsetX;
            int y = (area.getY() - 1) * VAKJE_GROOTTE + offsetY;

            int breedte = area.getBreedte() * VAKJE_GROOTTE;
            int hoogte = area.getHoogte() * VAKJE_GROOTTE;

            // Achtergrond kleur
            g.setColor(getKleur(area));
            g.fillRect(x, y, breedte, hoogte);

            // Rand
            g.setColor(Color.DARK_GRAY);
            Graphics2D g2 = (Graphics2D) g;
            g2.setStroke(new BasicStroke(2));
            g.drawRect(x, y, breedte, hoogte);
            g2.setStroke(new BasicStroke(1));

            // Label
            g.setColor(Color.BLACK);
            g.setFont(new Font("Arial", Font.BOLD, 12));
            String label = getLabel(area);
            FontMetrics fm = g.getFontMetrics();

            int textX = x + (breedte - fm.stringWidth(label)) / 2;
            int textY = y + (hoogte + fm.getAscent()) / 2 - 2;

            g.drawString(label, textX, textY);
        }

        // === TEKEN LIFT (BEWEGEND OBJECT) ===
        if (lift != null) {
            int liftX = (int)(lift.getX() * VAKJE_GROOTTE) + offsetX - VAKJE_GROOTTE/2;
            int liftY = (int)(lift.getY() * VAKJE_GROOTTE) + offsetY - VAKJE_GROOTTE/2;

            g.setColor(new Color(200, 100, 0));  // Oranje
            g.fillRect(liftX, liftY, VAKJE_GROOTTE, VAKJE_GROOTTE);

            g.setColor(Color.BLACK);
            Graphics2D g2d = (Graphics2D) g;
            g2d.setStroke(new BasicStroke(2));
            g.drawRect(liftX, liftY, VAKJE_GROOTTE, VAKJE_GROOTTE);

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            FontMetrics fm = g.getFontMetrics();
            int lx = liftX + (VAKJE_GROOTTE - fm.stringWidth("L")) / 2;
            int ly = liftY + (VAKJE_GROOTTE + fm.getAscent()) / 2 - 5;
            g.drawString("L", lx, ly);
        }

        // Teken alle personen
        for (Persoon persoon : hotel.getPersonen()) {
            if (persoon instanceof Gast) {
                Gast gast = (Gast) persoon;
                int px = (int)(gast.getX() * VAKJE_GROOTTE) + offsetX - 8;
                int py = (int)(gast.getY() * VAKJE_GROOTTE) + offsetY - 8;

                g.setColor(gast.getKleur());
                g.fillOval(px, py, 16, 16);

                g.setColor(new Color(
                        Math.max(0, gast.getKleur().getRed() - 80),
                        Math.max(0, gast.getKleur().getGreen() - 80),
                        Math.max(0, gast.getKleur().getBlue() - 80)
                ));
                g.drawOval(px, py, 16, 16);

                // Naam + activiteit boven de gast
                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.BOLD, 9));
                String label = gast.getNaam();
                if (!gast.getHuidigeActiviteit().isEmpty()) {
                    label += " " + gast.getHuidigeActiviteit();
                }
                g.drawString(label, px - 5, py - 5);
            } else if (persoon instanceof Schoonmaker) {
                Schoonmaker schoonmaker = (Schoonmaker) persoon;
                int px = (int)(schoonmaker.getX() * VAKJE_GROOTTE) + offsetX - 8;
                int py = (int)(schoonmaker.getY() * VAKJE_GROOTTE) + offsetY - 8;

                g.setColor(schoonmaker.getKleur());
                g.fillRect(px, py, 16, 16);

                g.setColor(Color.BLACK);
                g.drawRect(px, py, 16, 16);

                g.setColor(Color.BLACK);
                g.setFont(new Font("Arial", Font.BOLD, 10));
                g.drawString("S", px + 5, py + 8);

                // Activiteit label voor schoonmaker
                String label = "CM";
                if (!schoonmaker.getHuidigeActiviteit().isEmpty()) {
                    label += " " + schoonmaker.getHuidigeActiviteit();
                }
                g.setFont(new Font("Arial", Font.PLAIN, 8));
                g.drawString(label, px - 5, py - 3);
            }
        }

        // === US4.4: LEGENDA TOEVOEGEN ===
        tekenLegenda(g);

        // toon status (pause/active)
        if (!running) {
            g.setColor(new Color(0, 0, 0, 150));
            g.fillRect(0, 0, getWidth(), getHeight());

            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 30));
            g.drawString("PAUSED", getWidth() / 2 - 70, getHeight() / 2);
        }
    }

    /**
     * Hulpmethode voor US4.4: Tekent een legenda zodat de gebruiker de simulatie begrijpt.
     */
    private void tekenLegenda(Graphics g) {
        int lx = 10;
        int ly = getHeight() - 70;

        // Achtergrond legenda
        g.setColor(new Color(255, 255, 255, 220));
        g.fillRect(lx, ly, 130, 60);
        g.setColor(Color.BLACK);
        g.drawRect(lx, ly, 130, 60);

        g.setFont(new Font("Arial", Font.PLAIN, 11));

        // Gast
        g.setColor(Color.BLUE);
        g.fillOval(lx + 10, ly + 10, 10, 10);
        g.setColor(Color.BLACK);
        g.drawString("Gast", lx + 30, ly + 20);

        // Schoonmaker
        g.setColor(Color.DARK_GRAY);
        g.fillRect(lx + 10, ly + 25, 10, 10);
        g.setColor(Color.BLACK);
        g.drawString("Schoonmaker", lx + 30, ly + 35);

        // Lift
        g.setColor(new Color(200, 100, 0));
        g.fillRect(lx + 10, ly + 40, 10, 10);
        g.setColor(Color.BLACK);
        g.drawString("Lift", lx + 30, ly + 50);
    }

    // === US2.1: MOUSE EVENT HANDLERS ===

    /**
     * Detecteert clicks op personen, kamers en lobby
     * Priority: Personen > Kamers > Lobby
     */
    @Override
    public void mouseClicked(MouseEvent e) {
        if (hotel == null) return;

        int clickX = e.getX();
        int clickY = e.getY();

        // Bereken offsets
        int hotelBreedte = hotel.getBreedte() * VAKJE_GROOTTE;
        int hotelHoogte = hotel.getHoogte() * VAKJE_GROOTTE;
        int offsetX = (getWidth() - hotelBreedte) / 2;
        int offsetY = (getHeight() - hotelHoogte) / 2;

        // PRIORITY 1: Check personen (gasten en schoonmakers)
        for (Persoon persoon : hotel.getPersonen()) {
            if (isClickOnPerson(persoon, clickX, clickY, offsetX, offsetY)) {
                System.out.println("[Click]  Persoon aangeklikt: " + persoon.getNaam());
                if (onPersonClick != null) {
                    onPersonClick.accept(persoon);
                }
                return;
            }
        }

        // PRIORITY 2: Check kamers (rooms)
        for (Area area : hotel.getAreas()) {
            if ("Room".equals(area.getAreaType())) {
                if (isClickOnArea(area, clickX, clickY, offsetX, offsetY)) {
                    // Zoek de kamer met deze area
                    for (Kamer k : hotel.getKamers()) {
                        if (k.getArea() != null && k.getArea().equals(area)) {
                            System.out.println("[Click]  Kamer aangeklikt: " + k.getKamernummer());
                            if (onRoomClick != null) {
                                onRoomClick.accept(k);
                            }
                            return;
                        }
                    }
                }
            }
        }

        // PRIORITY 3: Check lobby
        for (Area area : hotel.getAreas()) {
            if ("Lobby".equals(area.getAreaType())) {
                if (isClickOnArea(area, clickX, clickY, offsetX, offsetY)) {
                    System.out.println("[US2.1]  Lobby aangeklikt - Gastenoverzicht openen");
                    if (onLobbyClick != null) {
                        onLobbyClick.run();
                    }
                    return;
                }
            }
        }
    }

    /**
     * Helpermethod: Check of click op een persoon valt (cirkeldetectie)
     */
    private boolean isClickOnPerson(Persoon persoon, int clickX, int clickY, int offsetX, int offsetY) {
        int px = (int)(persoon.getX() * VAKJE_GROOTTE) + offsetX - 8;
        int py = (int)(persoon.getY() * VAKJE_GROOTTE) + offsetY - 8;

        // Gast: cirkel met straal ~8
        if (persoon instanceof Gast) {
            int centerX = px + 8;
            int centerY = py + 8;
            int distance = (int) Math.sqrt(Math.pow(clickX - centerX, 2) + Math.pow(clickY - centerY, 2));
            return distance <= 10;  // Margin voor usability
        }

        // Schoonmaker: vierkant 16x16
        if (persoon instanceof Schoonmaker) {
            return clickX >= px && clickX <= px + 16 && clickY >= py && clickY <= py + 16;
        }

        return false;
    }

    /**
     * Helpermethod: Check of click op een area (rechthoek) valt
     */
    private boolean isClickOnArea(Area area, int clickX, int clickY, int offsetX, int offsetY) {
        int x = (area.getX() - 1) * VAKJE_GROOTTE + offsetX;
        int y = (area.getY() - 1) * VAKJE_GROOTTE + offsetY;
        int breedte = area.getBreedte() * VAKJE_GROOTTE;
        int hoogte = area.getHoogte() * VAKJE_GROOTTE;

        return clickX >= x && clickX <= x + breedte && clickY >= y && clickY <= y + hoogte;
    }

    @Override
    public void mousePressed(MouseEvent e) {}

    @Override
    public void mouseReleased(MouseEvent e) {}

    @Override
    public void mouseEntered(MouseEvent e) {}

    @Override
    public void mouseExited(MouseEvent e) {}

    @Override
    public void mouseDragged(MouseEvent e) {}

    @Override
    public void mouseMoved(MouseEvent e) {}

    private String getLabel(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                return area.getClassification() != null ?
                        area.getClassification().replace(" Star", "★") : "Kamer";
            case "Cinema": return "Bioscoop";
            case "Restaurant": return "Restaurant";
            case "Fitness": return "Fitness";
            case "Lobby": return "Lobby";
            case "Schacht": return "Schacht";
            case "Lift": return "Lift";
            case "Staircase": return "Trap";
            case "Storage": return "Opslag";
            default: return area.getAreaType();
        }
    }

    private Color getKleur(Area area) {
        switch (area.getAreaType()) {
            case "Room":
                String c = area.getClassification();
                if (c == null) return new Color(200, 230, 255);
                if (c.contains("1")) return new Color(200, 230, 255);
                if (c.contains("2")) return new Color(150, 200, 255);
                if (c.contains("3")) return new Color(100, 170, 255);
                if (c.contains("4")) return new Color(50, 130, 255);
                if (c.contains("5")) return new Color(0, 80, 200);
                return new Color(200, 230, 255);
            case "Lobby": return new Color(255, 220, 50);
            case "Schacht": return new Color(220, 220, 220);
            case "Lift": return new Color(255, 150, 0);
            case "Staircase": return new Color(100, 200, 100);
            case "Restaurant": return new Color(255, 100, 100);
            case "Cinema": return new Color(200, 100, 200);
            case "Fitness": return new Color(100, 220, 180);
            case "Storage": return new Color(180, 140, 100);
            default: return Color.WHITE;
        }
    }
}

package ui;

import model.Gast;
import model.Persoon;
import model.Schoonmaker;

import javax.swing.*;
import java.awt.*;

/**
 * Detail-venster voor persoon-informatie
 * Toont naam, type, activiteit, positie en huidge kamer (voor gasten)
 */
public class PersonDetailWindow extends JFrame {

    private Persoon persoon;

    public PersonDetailWindow(Persoon persoon) {
        this.persoon = persoon;

        String icon = getPersonIcon(persoon);
        setTitle(icon + " Details - " + persoon.getNaam());
        setSize(450, 350);
        setLocationRelativeTo(null);
        setDefaultCloseOperation(JFrame.DISPOSE_ON_CLOSE);
        setResizable(true);

        initializeUI();
    }

    private void initializeUI() {
        JPanel mainPanel = new JPanel();
        mainPanel.setLayout(new BoxLayout(mainPanel, BoxLayout.Y_AXIS));
        mainPanel.setBorder(BorderFactory.createEmptyBorder(15, 15, 15, 15));

        // Titel
        String icon = getPersonIcon(persoon);
        JLabel titleLabel = new JLabel(icon + " " + persoon.getNaam());
        titleLabel.setFont(new Font("Arial", Font.BOLD, 18));
        mainPanel.add(titleLabel);
        mainPanel.add(Box.createVerticalStrut(10));

        // Info-velden
        JPanel infoPanel = new JPanel();
        infoPanel.setLayout(new BoxLayout(infoPanel, BoxLayout.Y_AXIS));
        infoPanel.setBorder(BorderFactory.createLineBorder(Color.LIGHT_GRAY, 1));
        infoPanel.setBackground(new Color(245, 245, 245));

        // Naam
        addInfoRow(infoPanel, "Naam:", persoon.getNaam());

        // Type
        String typeLabel = (persoon instanceof Gast) ? " Gast" : " Schoonmaker";
        addInfoRow(infoPanel, "Type:", typeLabel);

        // Huidge Activiteit
        String activiteit = persoon.getHuidigeActiviteit();
        if (activiteit == null || activiteit.isEmpty()) {
            activiteit = "Onbekend";
        }
        addInfoRow(infoPanel, "Activiteit:", activiteit);

        // Positie
        String position = String.format("X: %.1f, Y: %.1f", persoon.getX(), persoon.getY());
        addInfoRow(infoPanel, "Positie:", position);

        // Extra info voor gasten
        if (persoon instanceof Gast) {
            Gast gast = (Gast) persoon;

            // Huidge Kamer
            String kamerInfo = (gast.getHuidigKamer() != null)
                ? "Kamer " + gast.getHuidigKamer().getKamernummer()
                : "Geen kamer";
            addInfoRow(infoPanel, "Huidge Kamer:", kamerInfo);

            // Evacuatie status
            if (gast.isFireAlarmActive()) {
                addInfoRow(infoPanel, "Brand-alarm:", " ACTIEF - Aan het evacueren!");
            }
        }

        // Extra info voor schoonmakers
        if (persoon instanceof Schoonmaker) {
            Schoonmaker schoonmaker = (Schoonmaker) persoon;
            addInfoRow(infoPanel, "Rol:", " Schoonmaak personeelslid");
        }

        mainPanel.add(infoPanel);
        mainPanel.add(Box.createVerticalStrut(10));

        // Status beschrijving
        JLabel descLabel = new JLabel("<html>" + getActivityDescription(persoon) + "</html>");
        descLabel.setFont(new Font("Arial", Font.ITALIC, 12));
        descLabel.setForeground(Color.DARK_GRAY);
        mainPanel.add(descLabel);

        mainPanel.add(Box.createVerticalGlue());

        // Sluit-knop
        JButton closeButton = new JButton("Sluiten");
        closeButton.setAlignmentX(Component.CENTER_ALIGNMENT);
        closeButton.addActionListener(e -> dispose());
        mainPanel.add(closeButton);

        add(mainPanel);
    }

    private void addInfoRow(JPanel panel, String label, String value) {
        JPanel rowPanel = new JPanel(new FlowLayout(FlowLayout.LEFT));
        rowPanel.setBackground(new Color(245, 245, 245));

        JLabel labelComp = new JLabel(label);
        labelComp.setFont(new Font("Arial", Font.BOLD, 12));
        labelComp.setPreferredSize(new Dimension(120, 20));

        JLabel valueComp = new JLabel(value);
        valueComp.setFont(new Font("Arial", Font.PLAIN, 12));
        valueComp.setMaximumSize(new Dimension(300, 30));

        rowPanel.add(labelComp);
        rowPanel.add(valueComp);
        panel.add(rowPanel);
    }

    private String getPersonIcon(Persoon p) {
        if (p instanceof Gast) {
            return "";
        } else if (p instanceof Schoonmaker) {
            return "";
        }
        return "";
    }

    private String getActivityDescription(Persoon p) {
        String activiteit = p.getHuidigeActiviteit();

        if (activiteit == null || activiteit.isEmpty()) {
            return "Geen activiteit op dit moment.";
        }

        if (activiteit.contains("Wandel")) {
            return "Deze persoon loopt door het hotel.";
        } else if (activiteit.contains("Lift")) {
            return "Deze persoon zit momenteel in de lift.";
        } else if (activiteit.contains("Eet") || activiteit.contains("Restaurant")) {
            return "Deze persoon geniet van het restaurant.";
        } else if (activiteit.contains("Sport") || activiteit.contains("Fitness")) {
            return "Deze persoon traint in de fitnessruimte.";
        } else if (activiteit.contains("Chill") || activiteit.contains("bed")) {
            return "Deze persoon ontspant in de kamer.";
        } else if (activiteit.contains("Schoon")) {
            return "Schoonmaker is kamers aan het schoonmaken.";
        } else if (activiteit.contains("EVACUATIE") || activiteit.contains("Evacu")) {
            return " NOOD: Deze persoon is aan het evacueren!";
        } else if (activiteit.contains("Vertrekt")) {
            return "Deze persoon verlaat het hotel.";
        }

        return "Activiteit: " + activiteit;
    }
}

package ui;

import model.Kamer;

import javax.swing.*;
import java.awt.*;

/**
 * Detail-venster voor kamer-informatie
 * Toont status, type, kamernummer en wie er verblijft
 */
public class RoomDetailWindow extends JFrame {

    private Kamer kamer;

    public RoomDetailWindow(Kamer kamer) {
        this.kamer = kamer;

        setTitle(" Kamer Details - " + getKamerLabel(kamer));
        setSize(400, 300);
        setLocationRelativeTo(null);
        setDefaultCloseOperation(JFrame.DISPOSE_ON_CLOSE);
        setResizable(true);

        initializeUI();
    }

    private void initializeUI() {
        JPanel mainPanel = new JPanel();
        mainPanel.setLayout(new BoxLayout(mainPanel, BoxLayout.Y_AXIS));
        mainPanel.setBorder(BorderFactory.createEmptyBorder(15, 15, 15, 15));

        // Titel
        JLabel titleLabel = new JLabel(" Kamer " + kamer.getKamernummer());
        titleLabel.setFont(new Font("Arial", Font.BOLD, 18));
        mainPanel.add(titleLabel);
        mainPanel.add(Box.createVerticalStrut(10));

        // Info-velden
        JPanel infoPanel = new JPanel();
        infoPanel.setLayout(new BoxLayout(infoPanel, BoxLayout.Y_AXIS));
        infoPanel.setBorder(BorderFactory.createLineBorder(Color.LIGHT_GRAY, 1));
        infoPanel.setBackground(new Color(245, 245, 245));

        // Kamernummer
        addInfoRow(infoPanel, "Kamernummer:", String.valueOf(kamer.getKamernummer()));

        // Type
        addInfoRow(infoPanel, "Type:", kamer.getType());

        // Status
        String statusEmoji = getStatusEmoji(kamer.getStatus());
        addInfoRow(infoPanel, "Status:", statusEmoji + " " + kamer.getStatus().toString());

        // Positie (area)
        if (kamer.getArea() != null) {
            String position = String.format("X: %d, Y: %d", kamer.getArea().getX(), kamer.getArea().getY());
            addInfoRow(infoPanel, "Positie:", position);
        }

        mainPanel.add(infoPanel);
        mainPanel.add(Box.createVerticalStrut(10));

        // Beschrijving van status
        JLabel descLabel = new JLabel(getStatusDescription(kamer.getStatus()));
        descLabel.setFont(new Font("Arial", Font.ITALIC, 12));
        descLabel.setForeground(Color.DARK_GRAY);
        mainPanel.add(descLabel);

        mainPanel.add(Box.createVerticalGlue());

        // Sluit-knop
        JButton closeButton = new JButton("Sluiten");
        closeButton.setAlignmentX(Component.CENTER_ALIGNMENT);
        closeButton.addActionListener(e -> dispose());
        mainPanel.add(closeButton);

        add(mainPanel);
    }

    private void addInfoRow(JPanel panel, String label, String value) {
        JPanel rowPanel = new JPanel(new FlowLayout(FlowLayout.LEFT));
        rowPanel.setBackground(new Color(245, 245, 245));

        JLabel labelComp = new JLabel(label);
        labelComp.setFont(new Font("Arial", Font.BOLD, 12));
        labelComp.setPreferredSize(new Dimension(100, 20));

        JLabel valueComp = new JLabel(value);
        valueComp.setFont(new Font("Arial", Font.PLAIN, 12));

        rowPanel.add(labelComp);
        rowPanel.add(valueComp);
        panel.add(rowPanel);
    }

    private String getKamerLabel(Kamer k) {
        return k.getKamernummer() + " (" + k.getType() + ")";
    }

    private String getStatusEmoji(Kamer.KamerStatus status) {
        switch (status) {
            case VRIJ: return "✅";
            case BEZET: return "";
            case SCHOONMAKEN: return "";
            default: return "";
        }
    }

    private String getStatusDescription(Kamer.KamerStatus status) {
        switch (status) {
            case VRIJ: return "Kamer is schoon en beschikbaar voor gasten.";
            case BEZET: return "Kamer is momenteel door een gast bewoond.";
            case SCHOONMAKEN: return "Schoonmaker is deze kamer aan het schoonmaken.";
            default: return "";
        }
    }
}

import model.Hotel;
import model.LayoutLoader;
import ui.HotelPanel;
import model.Simulator;
import model.Gast;
import model.SimulationClock;
import model.HTEClock;

import javax.swing.*;
import java.io.File;
import java.util.Arrays;

/**
 * De MainUI klasse is het startpunt van de applicatie.
 * Het regelt de GUI (Swing), de interactie met de gebruiker en de aansturing van de simulator.
 */
public class main {

    // --- VARIABELEN (State) ---
    private static HotelPanel hotelPanel;      // Het canvas waarop het hotel getekend wordt
    private static JComboBox<String> layoutDropdown; // Keuzemenu voor de JSON-bestanden
    private static JLabel statusLabel;         // Tekstbalk onderin voor statusberichten
    private static JLabel timestepLabel;       // Toont de huidige tijdstap (HTE)
    private static JButton startPauseButton;   // De knop die wisselt tussen Start en Pause
    private static Simulator simulator;        // De 'hersenen' van de simulatie (logica)

    /** * US2.3: De Timer is de 'hartslag' van de UI.
     * We maken er een variabele van zodat de slider de hartslag kan versnellen of vertragen.
     */
    private static Timer simulationTimer;

    public static void main(String[] args) {
        // SwingUtilities zorgt ervoor dat de UI veilig op de 'Event Dispatch Thread' draait.
        // Dit voorkomt dat je scherm vastloopt (freezes).
        SwingUtilities.invokeLater(() -> {
            try {
                // --- FRAME INITIALISATIE ---
                JFrame frame = new JFrame("Hotel Simulator");
                frame.setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE); // Stopt programma bij afsluiten

                // ControlPanel is de grijze balk bovenin met alle knoppen.
                JPanel controlPanel = new JPanel();
                controlPanel.add(new JLabel("Selecteer layout: "));

                // Haal de lijst met .json bestanden op uit de map 'layouts'.
                String[] layouts = getAvailableLayouts();
                layoutDropdown = new JComboBox<>(layouts);
                controlPanel.add(layoutDropdown);

                // --- KNOPPEN LOGICA ---

                // Laden-knop: roept de methode aan om een nieuw hotel in te laden.
                JButton loadButton = new JButton("Laden");
                loadButton.addActionListener(e -> loadLayout());
                controlPanel.add(loadButton);

                // Start/Pause-knop:
                startPauseButton = new JButton("Start");
                startPauseButton.addActionListener(e -> {
                    // Check of de simulator op dit moment draait
                    if (!simulator.isRunning()) {
                        simulator.start(); // Logische start
                        startPauseButton.setText("Pause"); // Verander tekst op knop
                        statusLabel.setText("Simulatie actief");
                    } else {
                        simulator.pause(); // Logische pauze
                        startPauseButton.setText("Resume"); // Verander tekst op knop
                        statusLabel.setText("Simulatie gepauzeerd");
                    }
                });
                controlPanel.add(startPauseButton);

                // --- US2.3: DE SNELHEID SLIDER ---
                // We maken een label om de huidige snelheid in tekst te tonen (ms).
                JLabel speedLabel = new JLabel("Delay: 500ms");

                /**
                 * JSlider(min, max, startwaarde).
                 * We gebruiken 50ms als snelste (1000ms / 50 = 20 ticks per sec).
                 * We gebruiken 1000ms als langzaamste (1 tick per sec).
                 */
                JSlider speedSlider = new JSlider(50, 1000, 500);

                // ChangeListener: wordt uitgevoerd zodra je het schuifje beweegt.
                speedSlider.addChangeListener(e -> {
                    int delay = speedSlider.getValue(); // Haal de nieuwe waarde uit de slider

                    if (simulationTimer != null) {
                        // Cruciaal: We vertellen de Timer dat hij minder lang moet wachten tussen ticks.
                        simulationTimer.setDelay(delay);
                    }
                    // Werk de tekst op het scherm bij.
                    speedLabel.setText("Delay: " + delay + "ms");
                });

                controlPanel.add(speedLabel);
                controlPanel.add(speedSlider);

                // --- LABELS VOOR INFORMATIE ---
                statusLabel = new JLabel("Hotel laden...");
                controlPanel.add(statusLabel);

                timestepLabel = new JLabel("Timestep: 0");
                controlPanel.add(timestepLabel);

                // --- EERSTE SETUP ---
                // We laden direct het eerste hotel uit de lijst zodat het scherm niet leeg is.
                Hotel hotel = LayoutLoader.laadLayout("layouts/" + layouts[0]);
                hotelPanel = new HotelPanel(hotel); // Maak het teken-veld aan
                addTestGuests(hotel); // Zet Alice, Bob en Charlie in het hotel

                // Maak de simulator-engine aan.
                simulator = new Simulator(hotel, hotelPanel);
                simulator.pause(); // De simulatie staat stil tot de gebruiker op Start klikt.

                // Voeg de onderdelen toe aan het hoofdvenster.
                frame.add(controlPanel, "North"); // Knoppen boven
                frame.add(hotelPanel, "Center"); // Hotel in het midden
                frame.pack(); // Maak venster precies groot genoeg
                frame.setLocationRelativeTo(null); // Centreer venster op scherm
                frame.setVisible(true); // Toon het venster

                /**
                 * DE KLOK (Timer) - HTE TICK ARCHITECTUUR:
                 * De timer 'vuurt' elke 50ms (UI refresh rate).
                 * De simulator bepaalt zelf via SimulationClock wanneer een echte HTE-tick moet plaatsvinden.
                 */
                simulationTimer = new Timer(50, e -> {
                    // Roep simulator.tick() aan - dit bepaalt intern of een HTE-tick nodig is
                    simulator.tick();

                    // Update UI met huidige timestep (alleen weergeven)
                    timestepLabel.setText("Timestep: " + simulator.getClock().getTimestep());
                });
                simulationTimer.start(); // De timer begint met 'lopen' op de achtergrond.

            } catch (Exception e) {
                // Foutopsporing: als er iets misgaat (bijv. bestand niet gevonden), zie je dat in de console.
                System.out.println("Fout: " + e.getMessage());
                e.printStackTrace();
            }
        });
    }

    /**
     * getAvailableLayouts:
     * Deze methode kijkt in de map 'layouts' en filtert alle bestanden die eindigen op .json.
     * Zo hoef je de namen van de bestanden niet hardcoded in je code te zetten.
     */
    private static String[] getAvailableLayouts() {
        File layoutDir = new File("layouts");
        String[] layouts = layoutDir.list((dir, name) -> name.endsWith(".json"));
        if (layouts == null || layouts.length == 0) {
            throw new RuntimeException("Fout: Geen .json layouts gevonden in de map.");
        }
        Arrays.sort(layouts); // Zet ze op alfabetische volgorde
        return layouts;
    }

    /**
     * loadLayout:
     * Wordt aangeroepen als je op de 'Laden' knop klikt.
     * Het 'ververst' het huidige hotel met een nieuw bestand.
     */
    private static void loadLayout() {
        try {
            // Pak de geselecteerde naam uit de dropdown
            String selectedLayout = (String) layoutDropdown.getSelectedItem();

            // Gebruik de LayoutLoader om de JSON te vertalen naar een Hotel-object
            Hotel newHotel = LayoutLoader.laadLayout("layouts/" + selectedLayout);

            // Geef het nieuwe hotel door aan het HotelPanel zodat de tekening verandert
            hotelPanel.setHotel(newHotel);

            addTestGuests(newHotel); // Zet de gasten weer terug op hun startpositie

            // Maak de simulator helemaal opnieuw aan voor het nieuwe hotel.
            simulator = new Simulator(newHotel, hotelPanel);
            simulator.resetClock(); // Belangrijk: De klok moet weer op 0 beginnen.
            simulator.pause(); // Het nieuwe hotel begint altijd gepauzeerd.

            // Reset de Start-knop tekst
            if (startPauseButton != null) {
                startPauseButton.setText("Start");
            }
            statusLabel.setText("Nieuw hotel geladen: " + selectedLayout);

        } catch (Exception e) {
            statusLabel.setText("Fout bij laden: " + e.getMessage());
        }
    }

    /**
     * addTestGuests:
     * Omdat we nog geen reserveringssysteem hebben, voegen we handmatig
     * drie Gast-objecten toe aan de lijst met personen in het Hotel.
     */
    private static void addTestGuests(Hotel hotel) {
        // Maak Alice aan op positie (2,2)
        Gast gast1 = new Gast("Alice", 2, 2);
        gast1.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast1.setHotel(hotel);  // Geef gast de hotel areas
        hotel.addPersoon(gast1);

        // Doe hetzelfde voor Bob en Charlie
        Gast gast2 = new Gast("Bob", 3, 3);
        gast2.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast2.setHotel(hotel);
        hotel.addPersoon(gast2);

        Gast gast3 = new Gast("Charlie", 1, 1);
        gast3.setGridBounds(hotel.getBreedte(), hotel.getHoogte());
        gast3.setHotel(hotel);
        hotel.addPersoon(gast3);
    }
}

